column1:
for (k in 1:nPopulation) {
    b0[k] ~ dnorm(b0_mu, sd = b0_sd)
}

{
    for (k in 1:nPopulation) {
        bAnnual[1, k] <- 0
        for (i in 2:nAnnual) {
            bAnnual[i, k] ~ dnorm(0, sd = bAnnual_sd)
        }
    }
}

{
    sMonth ~ dexp(sMonth_rate)
    for (i in 1:nMonth) {
        for (k in 1:nPopulation) {
            bMonth[i, k] ~ dnorm(0, sd = sMonth)
        }
    }
}

for (i in 1:nObs) {
    logit(eSurvival[i]) <- b0[PopulationName[i]] + bAnnual[Annual[i], PopulationName[i]] + bYear[PopulationName[i]] * CaribouYear[i] + bMonth[Month[i], PopulationName[i]]
}

for (i in 1:nObs) {
    Mortalities[i] ~ dbin(1 - eSurvival[i], StartTotal[i])
}
